from sqlalchemy.orm import Session

from app.models.audio_item import AudioItem
from app.schemas.audio_item import AudioItemCreate, AudioItemUpdate


def get_audio_items(db: Session, project_id: int) -> list[AudioItem]:
    return (
        db.query(AudioItem)
        .filter(AudioItem.project_id == project_id)
        .order_by(AudioItem.created_at.asc())
        .all()
    )


def get_audio_item(db: Session, item_id: int) -> AudioItem | None:
    return db.query(AudioItem).filter(AudioItem.id == item_id).first()


def create_audio_item(db: Session, project_id: int, data: AudioItemCreate) -> AudioItem:
    item = AudioItem(
        project_id=project_id,
        text_content=data.text_content,
        audio_url=data.audio_url,
        original_filename=data.original_filename,
    )
    db.add(item)
    db.commit()
    db.refresh(item)
    return item


def update_audio_item(db: Session, item_id: int, data: AudioItemUpdate) -> AudioItem | None:
    item = get_audio_item(db, item_id)
    if not item:
        return None
    if data.text_content is not None:
        item.text_content = data.text_content
    if data.audio_url is not None:
        item.audio_url = data.audio_url
    if data.original_filename is not None:
        item.original_filename = data.original_filename
    db.commit()
    db.refresh(item)
    return item


def delete_audio_item(db: Session, item_id: int) -> bool:
    item = get_audio_item(db, item_id)
    if not item:
        return False
    db.delete(item)
    db.commit()
    return True

