from fastapi import APIRouter, HTTPException

from app.api.deps import DBSession
from app.schemas.project import ProjectCreate, ProjectResponse, ProjectUpdate
from app.services import project_service

router = APIRouter(prefix="/projects")


@router.get("", response_model=list[ProjectResponse])
def list_projects(db: DBSession):
    return project_service.get_projects(db)


@router.post("", response_model=ProjectResponse, status_code=201)
def create_project(data: ProjectCreate, db: DBSession):
    return project_service.create_project(db, data)


@router.get("/{project_id}", response_model=ProjectResponse)
def get_project(project_id: int, db: DBSession):
    project = project_service.get_project(db, project_id)
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    # add audio_count
    from sqlalchemy import func
    from app.models.audio_item import AudioItem
    count = db.query(func.count(AudioItem.id)).filter(AudioItem.project_id == project_id).scalar() or 0
    return {
        "id": project.id,
        "name": project.name,
        "description": project.description,
        "created_at": project.created_at,
        "updated_at": project.updated_at,
        "audio_count": count,
    }


@router.put("/{project_id}", response_model=ProjectResponse)
def update_project(project_id: int, data: ProjectUpdate, db: DBSession):
    project = project_service.update_project(db, project_id, data)
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    from sqlalchemy import func
    from app.models.audio_item import AudioItem
    count = db.query(func.count(AudioItem.id)).filter(AudioItem.project_id == project_id).scalar() or 0
    return {
        "id": project.id,
        "name": project.name,
        "description": project.description,
        "created_at": project.created_at,
        "updated_at": project.updated_at,
        "audio_count": count,
    }


@router.delete("/{project_id}")
def delete_project(project_id: int, db: DBSession):
    deleted = project_service.delete_project(db, project_id)
    if not deleted:
        raise HTTPException(status_code=404, detail="Project not found")
    return {"message": "Project deleted"}

