from fastapi import APIRouter, HTTPException

from app.api.deps import DBSession
from app.schemas.audio_item import AudioItemCreate, AudioItemResponse, AudioItemUpdate
from app.services import audio_service, project_service

router = APIRouter(prefix="/projects/{project_id}/audio-items")


@router.get("", response_model=list[AudioItemResponse])
def list_audio_items(project_id: int, db: DBSession):
    project = project_service.get_project(db, project_id)
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    return audio_service.get_audio_items(db, project_id)


@router.post("", response_model=AudioItemResponse, status_code=201)
def create_audio_item(project_id: int, data: AudioItemCreate, db: DBSession):
    project = project_service.get_project(db, project_id)
    if not project:
        raise HTTPException(status_code=404, detail="Project not found")
    return audio_service.create_audio_item(db, project_id, data)


@router.put("/{item_id}", response_model=AudioItemResponse)
def update_audio_item(project_id: int, item_id: int, data: AudioItemUpdate, db: DBSession):
    item = audio_service.update_audio_item(db, item_id, data)
    if not item:
        raise HTTPException(status_code=404, detail="Audio item not found")
    return item


@router.delete("/{item_id}")
def delete_audio_item(project_id: int, item_id: int, db: DBSession):
    deleted = audio_service.delete_audio_item(db, item_id)
    if not deleted:
        raise HTTPException(status_code=404, detail="Audio item not found")
    return {"message": "Audio item deleted"}

