/* =============================================
   AudioVault — Dark industrial aesthetic
   Fonts: Syne (display) + DM Mono (body/code)
   ============================================= */

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

:root {
  --font-display: 'Syne', sans-serif;
  --font-mono: 'DM Mono', monospace;

  --bg:        #0d0d0d;
  --surface:   #161616;
  --surface-2: #1e1e1e;
  --border:    #2a2a2a;
  --border-hi: #3d3d3d;

  --ink:       #e8e4dc;
  --ink-2:     #8a8680;
  --ink-3:     #4a4744;

  --accent:    #c8f545;   /* sharp lime-yellow */
  --accent-2:  #ff6b35;   /* warm orange for danger */
  --success:   #4ade80;
  --error:     #f87171;

  --r-sm: 4px;
  --r-md: 8px;
  --r-lg: 12px;

  --ease: cubic-bezier(0.4, 0, 0.2, 1);
}

html, body {
  height: 100%;
  font-family: var(--font-mono);
  font-size: 14px;
  color: var(--ink);
  background: var(--bg);
  line-height: 1.6;
  -webkit-font-smoothing: antialiased;
}

/* ─── Noise texture ─────────────────────────── */
.noise {
  position: fixed; inset: 0;
  pointer-events: none; z-index: 0;
  opacity: .03;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)'/%3E%3C/svg%3E");
  background-size: 200px;
}

/* ─── Header ────────────────────────────────── */
.header {
  position: sticky; top: 0; z-index: 100;
  background: var(--bg);
  border-bottom: 1px solid var(--border);
  backdrop-filter: blur(8px);
}
.header__inner {
  max-width: 1100px; margin: 0 auto;
  padding: 14px 24px;
  display: flex; align-items: center; justify-content: space-between;
}
.header__brand { display: flex; align-items: center; gap: 10px; }
.header__dot {
  width: 10px; height: 10px;
  border-radius: 50%;
  background: var(--accent);
  box-shadow: 0 0 12px var(--accent);
  animation: pulse 2.5s ease-in-out infinite;
}
@keyframes pulse {
  0%, 100% { opacity: 1; box-shadow: 0 0 8px var(--accent); }
  50%       { opacity: .6; box-shadow: 0 0 18px var(--accent); }
}
.header__name {
  font-family: var(--font-display);
  font-size: 18px; font-weight: 800;
  letter-spacing: -.3px;
  color: var(--ink);
}
.header__count {
  font-size: 11px; color: var(--ink-2);
  font-family: var(--font-mono);
  letter-spacing: .5px;
}

/* ─── Main ──────────────────────────────────── */
.main {
  max-width: 1100px; margin: 0 auto;
  padding: 40px 24px 80px;
  position: relative; z-index: 1;
}

/* ─── Views ─────────────────────────────────── */
.view { display: none; }
.view--active { display: block; animation: fadeUp .3s var(--ease) both; }
@keyframes fadeUp {
  from { opacity: 0; transform: translateY(16px); }
  to   { opacity: 1; transform: translateY(0); }
}

/* ─── View header ───────────────────────────── */
.view-header {
  display: flex; align-items: flex-start;
  justify-content: space-between; gap: 16px;
  margin-bottom: 36px;
  flex-wrap: wrap;
}
.view-title {
  font-family: var(--font-display);
  font-size: clamp(28px, 4vw, 42px);
  font-weight: 800; line-height: 1.1;
  letter-spacing: -1px;
  color: var(--ink);
}
.view-sub {
  font-size: 13px; color: var(--ink-2);
  margin-top: 4px;
}
.header-actions { display: flex; gap: 8px; align-items: center; flex-wrap: wrap; }

/* ─── State containers ──────────────────────── */
.state-container { margin-bottom: 16px; }
.state-loading {
  display: flex; align-items: center; gap: 10px;
  color: var(--ink-2); font-size: 13px; padding: 24px 0;
}
.spinner {
  width: 16px; height: 16px;
  border: 2px solid var(--border-hi);
  border-top-color: var(--accent);
  border-radius: 50%;
  animation: spin .7s linear infinite;
}
@keyframes spin { to { transform: rotate(360deg); } }
.state-error {
  padding: 12px 16px; border-radius: var(--r-md);
  background: rgba(248,113,113,.08);
  border: 1px solid rgba(248,113,113,.25);
  color: var(--error); font-size: 13px;
}
.state-empty {
  padding: 48px 0; text-align: center; color: var(--ink-3);
}
.state-empty__icon { font-size: 36px; margin-bottom: 12px; opacity: .4; }
.state-empty__text { font-size: 14px; }
.state-empty__sub  { font-size: 12px; color: var(--ink-3); margin-top: 4px; }

/* ─── Buttons ───────────────────────────────── */
button { cursor: pointer; font-family: var(--font-mono); }

.btn {
  display: inline-flex; align-items: center; gap: 6px;
  padding: 9px 16px; border-radius: var(--r-md);
  font-size: 13px; font-weight: 500;
  border: 1px solid transparent;
  transition: all 150ms var(--ease);
  white-space: nowrap; user-select: none;
  text-decoration: none;
}
.btn:disabled { opacity: .4; pointer-events: none; }

.btn--create {
  background: var(--accent); color: #0d0d0d;
  border-color: var(--accent); font-weight: 700;
}
.btn--create:hover { background: #d4fb5a; }

.btn--ghost {
  background: transparent; color: var(--ink-2);
  border-color: var(--border-hi);
}
.btn--ghost:hover { color: var(--ink); border-color: var(--ink-3); background: var(--surface); }

.btn--delete {
  background: transparent; color: var(--accent-2);
  border-color: rgba(255,107,53,.35);
}
.btn--delete:hover { background: rgba(255,107,53,.1); }

.btn--back {
  background: transparent; color: var(--ink-2);
  border: none; padding: 0; font-size: 12px;
  letter-spacing: .5px; margin-bottom: 4px;
}
.btn--back:hover { color: var(--ink); }

.btn--xs { padding: 4px 10px; font-size: 11px; }

/* ─── Projects grid ─────────────────────────── */
.projects-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
  gap: 16px;
}

.project-card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--r-lg);
  padding: 24px;
  cursor: pointer;
  transition: border-color 180ms var(--ease), transform 180ms var(--ease);
  position: relative;
  overflow: hidden;
  animation: fadeUp .35s var(--ease) both;
}
.project-card:hover {
  border-color: var(--accent);
  transform: translateY(-2px);
}
.project-card::before {
  content: '';
  position: absolute; top: 0; left: 0; right: 0;
  height: 2px;
  background: var(--accent);
  transform: scaleX(0); transform-origin: left;
  transition: transform 180ms var(--ease);
}
.project-card:hover::before { transform: scaleX(1); }

.project-card__name {
  font-family: var(--font-display);
  font-size: 18px; font-weight: 700;
  color: var(--ink); margin-bottom: 6px;
  word-break: break-word;
}
.project-card__desc {
  font-size: 12px; color: var(--ink-2);
  margin-bottom: 16px; line-height: 1.5;
  display: -webkit-box; -webkit-line-clamp: 2;
  -webkit-box-orient: vertical; overflow: hidden;
}
.project-card__meta {
  display: flex; align-items: center; justify-content: space-between;
  padding-top: 16px; border-top: 1px solid var(--border);
}
.project-card__count {
  font-size: 11px; color: var(--ink-3);
  display: flex; align-items: center; gap: 4px;
}
.project-card__count-num {
  font-size: 20px; font-weight: 700;
  font-family: var(--font-display);
  color: var(--accent); line-height: 1;
}
.project-card__arrow { color: var(--ink-3); font-size: 16px; }

/* ─── Audio list ────────────────────────────── */
.audio-list { display: flex; flex-direction: column; gap: 12px; }

.audio-item {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--r-lg);
  padding: 20px 24px;
  display: grid;
  grid-template-columns: 1fr auto;
  gap: 16px; align-items: start;
  animation: fadeUp .3s var(--ease) both;
  transition: border-color 150ms;
}
.audio-item:hover { border-color: var(--border-hi); }

.audio-item__idx {
  font-size: 10px; color: var(--ink-3);
  font-family: var(--font-mono);
  margin-bottom: 8px;
  letter-spacing: .5px;
}
.audio-item__text {
  font-size: 14px; color: var(--ink);
  line-height: 1.65; white-space: pre-wrap;
  word-break: break-word; margin-bottom: 12px;
}
.audio-item__player {
  margin-top: 4px;
}
.audio-item__player audio {
  width: 100%; max-width: 420px;
  height: 36px; border-radius: var(--r-sm);
  accent-color: var(--accent);
}
.audio-item__no-audio {
  font-size: 11px; color: var(--ink-3);
  margin-top: 4px;
}
.audio-item__actions {
  display: flex; gap: 6px; flex-direction: column;
  align-items: flex-end;
}

/* ─── Modal ─────────────────────────────────── */
.backdrop {
  position: fixed; inset: 0; z-index: 200;
  background: rgba(0,0,0,.75);
  backdrop-filter: blur(4px);
  display: flex; align-items: center; justify-content: center;
  padding: 16px;
  opacity: 0; pointer-events: none;
  transition: opacity 200ms var(--ease);
}
.backdrop.open {
  opacity: 1; pointer-events: all;
}
.modal {
  background: var(--surface);
  border: 1px solid var(--border-hi);
  border-radius: var(--r-lg);
  padding: 28px;
  width: 100%; max-width: 480px;
  max-height: 90vh; overflow-y: auto;
  transform: translateY(20px) scale(.97);
  transition: transform 220ms var(--ease);
  position: relative; z-index: 1;
}
.backdrop.open .modal {
  transform: translateY(0) scale(1);
}
.modal--wide { max-width: 620px; }
.modal--sm   { max-width: 360px; }

.modal__head {
  display: flex; align-items: center; justify-content: space-between;
  margin-bottom: 20px;
}
.modal__title {
  font-family: var(--font-display);
  font-size: 18px; font-weight: 700; color: var(--ink);
}
.modal__x {
  background: none; border: none;
  color: var(--ink-3); font-size: 16px; padding: 2px 6px;
  border-radius: var(--r-sm);
  transition: color 150ms, background 150ms;
}
.modal__x:hover { color: var(--ink); background: var(--surface-2); }

.modal__foot {
  display: flex; justify-content: flex-end; gap: 8px;
  margin-top: 24px;
}

.confirm-msg {
  color: var(--ink-2); font-size: 14px;
  margin-bottom: 20px; line-height: 1.5;
}

/* ─── Form fields ───────────────────────────── */
.field { margin-bottom: 16px; }
.field__label {
  display: block; font-size: 11px;
  color: var(--ink-2); margin-bottom: 6px;
  letter-spacing: .5px; text-transform: uppercase;
}
.field__hint { color: var(--ink-3); font-size: 10px; }
.req { color: var(--accent-2); }
.field__input {
  width: 100%; padding: 10px 14px;
  background: var(--surface-2);
  border: 1px solid var(--border-hi);
  border-radius: var(--r-md);
  color: var(--ink); font-family: var(--font-mono); font-size: 14px;
  outline: none;
  transition: border-color 150ms, box-shadow 150ms;
}
.field__input:focus {
  border-color: var(--accent);
  box-shadow: 0 0 0 3px rgba(200,245,69,.12);
}
.field__ta { resize: vertical; min-height: 80px; }
.field__err { display: block; color: var(--error); font-size: 11px; margin-top: 4px; }

/* ─── Drop zone ─────────────────────────────── */
.dropzone {
  border: 1.5px dashed var(--border-hi);
  border-radius: var(--r-lg);
  padding: 32px 16px;
  text-align: center;
  color: var(--ink-2);
  position: relative;
  transition: border-color 150ms, background 150ms;
}
.dropzone.drag-over {
  border-color: var(--accent);
  background: rgba(200,245,69,.04);
}
.dropzone__input {
  position: absolute; inset: 0; width: 100%; height: 100%;
  opacity: 0; cursor: pointer;
}
/* hide native input behind pick label when done/uploading */
.dropzone__icon { font-size: 32px; margin-bottom: 8px; opacity: .4; }
.dropzone__pick { color: var(--accent); cursor: pointer; text-decoration: underline; }
