/* =============================================
   AudioVault — Main Application
   ============================================= */

// ─── State ───────────────────────────────────
const state = {
  currentProjectId: null,
  currentProjectName: '',
  editingProjectId: null,
  editingItemId: null,
  pendingAudioUrl: null,
  pendingAudioFilename: null,
  confirmCallback: null,
};

// ─── DOM refs ─────────────────────────────────
const $ = id => document.getElementById(id);

const views = {
  projects: $('view-projects'),
  detail:   $('view-detail'),
};

// ─── Bootstrap ───────────────────────────────
document.addEventListener('DOMContentLoaded', () => {
  setupModalClosers();
  setupProjectForm();
  setupItemForm();
  setupConfirmModal();
  setupDropzone();

  $('btn-new-project').addEventListener('click', () => openProjectModal(null));
  $('btn-back').addEventListener('click', showProjectsView);
  $('btn-add-item').addEventListener('click', () => openItemModal(null));
  $('btn-edit-project').addEventListener('click', () => openProjectModal(state.currentProjectId));
  $('btn-delete-project').addEventListener('click', confirmDeleteProject);

  showProjectsView();
});

// ─── Views ───────────────────────────────────
function showProjectsView() {
  views.projects.classList.add('view--active');
  views.detail.classList.remove('view--active');
  state.currentProjectId = null;
  loadProjects();
}

function showDetailView(projectId, projectName, projectDesc) {
  state.currentProjectId = projectId;
  state.currentProjectName = projectName;
  $('detail-name').textContent = projectName;
  $('detail-desc').textContent = projectDesc || '';
  views.projects.classList.remove('view--active');
  views.detail.classList.add('view--active');
  loadAudioItems(projectId);
}

// ─── Projects ─────────────────────────────────
async function loadProjects() {
  const stateEl = $('projects-state');
  const grid    = $('projects-grid');
  grid.innerHTML = '';
  showStateLoading(stateEl, 'Đang tải...');

  try {
    const projects = await api.get('/api/projects');
    clearState(stateEl);
    $('header__count') && ($('header__count').textContent = `${projects.length} projects`);
    document.querySelector('.header__count').textContent = `${projects.length} project${projects.length !== 1 ? 's' : ''}`;

    if (projects.length === 0) {
      showStateEmpty(stateEl, '♫', 'Chưa có project nào', 'Nhấn "Tạo project" để bắt đầu');
      return;
    }
    projects.forEach((p, i) => {
      const card = createProjectCard(p, i);
      grid.appendChild(card);
    });
  } catch (err) {
    showStateError(stateEl, err.message);
  }
}

function createProjectCard(project, index) {
  const div = document.createElement('div');
  div.className = 'project-card';
  div.style.animationDelay = `${index * 60}ms`;
  div.innerHTML = `
    <div class="project-card__name">${escapeHtml(project.name)}</div>
    <div class="project-card__desc">${escapeHtml(project.description || 'Không có mô tả')}</div>
    <div class="project-card__meta">
      <div class="project-card__count">
        <span class="project-card__count-num">${project.audio_count}</span>&nbsp;mục audio
      </div>
      <span class="project-card__arrow">→</span>
    </div>
  `;
  div.addEventListener('click', () => showDetailView(project.id, project.name, project.description));
  return div;
}

// ─── Project Modal ────────────────────────────
function openProjectModal(projectId) {
  state.editingProjectId = projectId;
  const isEdit = projectId !== null;
  $('modal-project-title').textContent = isEdit ? 'Sửa project' : 'Tạo project mới';
  $('btn-submit-project').textContent  = isEdit ? 'Lưu' : 'Tạo';
  $('err-project-name').textContent = '';

  if (isEdit) {
    $('inp-project-name').value = state.currentProjectName;
    $('inp-project-desc').value = $('detail-desc').textContent;
  } else {
    $('form-project').reset();
  }
  openModal('modal-project');
}

function setupProjectForm() {
  $('form-project').addEventListener('submit', async (e) => {
    e.preventDefault();
    const name = $('inp-project-name').value.trim();
    if (!name) { $('err-project-name').textContent = 'Tên project là bắt buộc'; return; }
    $('err-project-name').textContent = '';

    const payload = {
      name,
      description: $('inp-project-desc').value.trim() || null,
    };

    const btn = $('btn-submit-project');
    btn.disabled = true;

    try {
      if (state.editingProjectId) {
        await api.put(`/api/projects/${state.editingProjectId}`, payload);
        closeModal('modal-project');
        toast('Project đã được cập nhật', 'success');
        // update detail header
        $('detail-name').textContent = payload.name;
        $('detail-desc').textContent = payload.description || '';
        state.currentProjectName = payload.name;
      } else {
        const created = await api.post('/api/projects', payload);
        closeModal('modal-project');
        toast('Tạo project thành công', 'success');
        showDetailView(created.id, created.name, created.description);
      }
    } catch (err) {
      toast(err.message, 'error');
    } finally {
      btn.disabled = false;
    }
  });
}

function confirmDeleteProject() {
  $('confirm-msg').textContent = `Xoá project "${state.currentProjectName}"? Tất cả mục audio cũng sẽ bị xoá.`;
  state.confirmCallback = async () => {
    try {
      await api.delete(`/api/projects/${state.currentProjectId}`);
      closeModal('modal-confirm');
      toast('Đã xoá project', 'success');
      showProjectsView();
    } catch (err) {
      toast(err.message, 'error');
    }
  };
  openModal('modal-confirm');
}

// ─── Audio Items ──────────────────────────────
async function loadAudioItems(projectId) {
  const stateEl = $('items-state');
  const list    = $('audio-items-list');
  list.innerHTML = '';
  showStateLoading(stateEl, 'Đang tải...');

  try {
    const items = await api.get(`/api/projects/${projectId}/audio-items`);
    clearState(stateEl);

    if (items.length === 0) {
      showStateEmpty(stateEl, '♪', 'Chưa có mục nào', 'Nhấn "+ Thêm mục" để thêm cặp text-audio đầu tiên');
      return;
    }
    items.forEach((item, i) => {
      list.appendChild(createAudioItemEl(item, i + 1));
    });
  } catch (err) {
    showStateError(stateEl, err.message);
  }
}

function createAudioItemEl(item, index) {
  const div = document.createElement('div');
  div.className = 'audio-item';
  div.style.animationDelay = `${(index - 1) * 40}ms`;
  div.id = `item-${item.id}`;

  const audioHtml = item.audio_url
    ? `<div class="audio-item__player">
         <audio controls preload="none" src="${escapeHtml(item.audio_url)}"></audio>
       </div>`
    : `<p class="audio-item__no-audio">— chưa có audio —</p>`;

  div.innerHTML = `
    <div>
      <div class="audio-item__idx">#${String(index).padStart(3, '0')} · ${item.original_filename ? escapeHtml(item.original_filename) : 'no file'}</div>
      <div class="audio-item__text">${escapeHtml(item.text_content)}</div>
      ${audioHtml}
    </div>
    <div class="audio-item__actions">
      <button class="btn btn--ghost btn--xs" onclick="openItemModal(${item.id})">Sửa</button>
      <button class="btn btn--delete btn--xs" onclick="confirmDeleteItem(${item.id})">Xoá</button>
    </div>
  `;
  return div;
}

// ─── Item Modal ───────────────────────────────
function openItemModal(itemId) {
  state.editingItemId = itemId;
  state.pendingAudioUrl = null;
  state.pendingAudioFilename = null;

  $('modal-item-title').textContent = itemId ? 'Sửa mục' : 'Thêm mục mới';
  $('btn-submit-item').textContent  = itemId ? 'Lưu' : 'Thêm';
  $('err-item-text').textContent = '';
  $('form-item').reset();
  resetDropzone();

  if (itemId) {
    // find existing item data from DOM
    const el = $(`item-${itemId}`);
    if (el) {
      const textEl = el.querySelector('.audio-item__text');
      if (textEl) $('inp-item-text').value = textEl.textContent;
      const audioEl = el.querySelector('audio');
      if (audioEl) {
        state.pendingAudioUrl = audioEl.src;
        const idx = el.querySelector('.audio-item__idx');
        const fname = idx ? idx.textContent.split('·')[1]?.trim() : null;
        if (fname && fname !== 'no file') {
          state.pendingAudioFilename = fname;
          showDropzoneDone(fname);
        }
      }
    }
  }
  openModal('modal-item');
}

function setupItemForm() {
  $('form-item').addEventListener('submit', async (e) => {
    e.preventDefault();
    const text = $('inp-item-text').value.trim();
    if (!text) { $('err-item-text').textContent = 'Nội dung văn bản là bắt buộc'; return; }
    $('err-item-text').textContent = '';

    const payload = {
      text_content: text,
      audio_url:  state.pendingAudioUrl || null,
      original_filename: state.pendingAudioFilename || null,
    };

    const btn = $('btn-submit-item');
    btn.disabled = true;

    try {
      if (state.editingItemId) {
        await api.put(`/api/projects/${state.currentProjectId}/audio-items/${state.editingItemId}`, payload);
        toast('Đã cập nhật mục', 'success');
      } else {
        await api.post(`/api/projects/${state.currentProjectId}/audio-items`, payload);
        toast('Đã thêm mục mới', 'success');
      }
      closeModal('modal-item');
      loadAudioItems(state.currentProjectId);
    } catch (err) {
      toast(err.message, 'error');
    } finally {
      btn.disabled = false;
    }
  });
}

function confirmDeleteItem(itemId) {
