) state.confirmCallback();', '+  });', '+}', '+', '+// ─── Dropzone / S3 upload ──────────────────────', '+function setupDropzone() {', "+  const dz  = $('dropzone');", "+  const inp = $('inp-item-audio');", "+  const rmBtn = $('btn-rm-audio');", '+', "+  inp.addEventListener('change', () => {", '+    if (inp.files[0]) handleAudioFile(inp.files[0]);', '+  });', '+', "+  dz.addEventListener('dragover', e => { e.preventDefault(); dz.classList.add('drag-over'); });", "+  dz.addEventListener('dragleave', () => dz.classList.remove('drag-over'));", "+  dz.addEventListener('drop', e => {", "+    e.preventDefault(); dz.classList.remove('drag-over');", '+    const file = e.dataTransfer.files[0];', "+    if (file && file.type.startsWith('audio/')) handleAudioFile(file);", "+    else toast('Vui lòng chọn file audio hợp lệ', 'error');", '+  });', '+', "+  rmBtn.addEventListener('click', () => {", '+    state.pendingAudioUrl = null;', '+    state.pendingAudioFilename = null;', '+    resetDropzone();', '+  });', '+}', '+', '+async function handleAudioFile(file) {', "+  if (file.size > 50 * 1024 * 1024) { toast('File quá lớn (tối đa 50MB)', 'error'); return; }", '+', '+  showDropzoneUploading();', "+  $('btn-submit-item').disabled = true;", '+', '+  try {', '+    // Get presigned URL from backend', "+    const { upload_url, file_url } = await api.post('/api/upload/presigned-url', { filename: file.name });", '+', '+    // Upload to S3', '+    const xhr = new XMLHttpRequest();', "+    xhr.open('PUT', upload_url);", "+    xhr.setRequestHeader('Content-Type', file.type || 'audio/mpeg');", '+', '+    xhr.upload.onprogress = (e) => {', '+      if (e.lengthComputable) {', '+        const pct = Math.round((e.loaded / e.total) * 100);', "+        $('prog-fill').style.width = pct + '%';", "+        $('dz-status').textContent = `Đang upload… ${pct}%`;", '+      }', '+    };', '+', '+    await new Promise((resolve, reject) => {', '+      xhr.onload = () => xhr.status >= 200 && xhr.status < 30