ist.add('open');", "+  el.setAttribute('aria-hidden', 'false');", "+  document.body.style.overflow = 'hidden';", '+}', '+', '+function closeModal(id) {', '+  const el = $(id);', "+  el.classList.remove('open');", "+  el.setAttribute('aria-hidden', 'true');", "+  document.body.style.overflow = '';", '+}', '+', '+function setupModalClosers() {', "+  document.querySelectorAll('[data-close]').forEach(btn => {", "+    btn.addEventListener('click', () => closeModal(btn.dataset.close));", '+  });', "+  document.querySelectorAll('.backdrop').forEach(backdrop => {", "+    backdrop.addEventListener('click', (e) => {", '+      if (e.target === backdrop) closeModal(backdrop.id);', '+    });', '+  });', "+  document.addEventListener('keydown', (e) => {", "+    if (e.key === 'Escape') {", "+      document.querySelectorAll('.backdrop.open').forEach(el => closeModal(el.id));", '     }', '-    return data;', '+  });', ' }', '+', '+// ─── State helpers ────────────────────────────', "+function showStateLoading(el, msg = 'Đang tải…') {", '+  el.innerHTML = `<div class="state-loading"><div class="spinner"></div>${escapeHtml(msg)}</div>`;', '+}', '+function showStateError(el, msg) {', '+  el.innerHTML = `<div class="state-error">Lỗi: ${escapeHtml(msg)}</div>`;', '+}', "+function showStateEmpty(el, icon, text, sub = '') {", '+  el.innerHTML = `', '+    <div class="state-empty">', '+      <div class="state-empty__icon">${icon}</div>', '+      <p class="state-empty__text">${escapeHtml(text)}</p>', '+      ${sub ? `<p class="state-empty__sub">${escapeHtml(sub)}</p>` : ''}', '+    </div>`;', '+}', "+function clearState(el) { el.innerHTML = ''; }", '+', '+// ─── Toast ────────────────────────────────────', "+function toast(msg, type = 'info') {", "+  const t = document.createElement('div');", '+  t.className = `toast toast--${type}`;', '+  t.textContent = msg;', "+  $('toasts').appendChild(t);", '+  setTimeout(() => t.remove(), 3500);', '+}', '+', '+// ─── Util ───────────────────────────────